     1→import { auth, currentUser } from "@clerk/nextjs/server";
     2→import { prisma } from "@compass/db";
     3→
     4→export async function requireStudent() {
     5→  const { userId } = await auth();
     6→  if (!userId) {
     7→    throw new Error("Unauthorized");
     8→  }
     9→
    10→  const student = await prisma.student.findUnique({
    11→    where: { clerkId: userId },
    12→    include: {
    13→      school: true,
    14→      privacySettings: true,
    15→      notificationPrefs: true,
    16→    },
    17→  });
    18→
    19→  if (!student) {
    20→    throw new Error("Student not found");
    21→  }
    22→
    23→  return student;
    24→}
    25→
    26→export async function requireCounselor() {
    27→  const { userId } = await auth();
    28→  if (!userId) {
    29→    throw new Error("Unauthorized");
    30→  }
    31→
    32→  const counselor = await prisma.counselor.findUnique({
    33→    where: { clerkId: userId },
    34→    include: {
    35→      school: true,
    36→    },
    37→  });
    38→
    39→  if (!counselor) {
    40→    throw new Error("Counselor not found");
    41→  }
    42→
    43→  return counselor;
    44→}
    45→
    46→export async function getStudentOrNull() {
    47→  try {
    48→    return await requireStudent();
    49→  } catch {
    50→    return null;
    51→  }
    52→}
    53→
    54→export async function getCurrentUserId(): Promise<string | null> {
    55→  const { userId } = await auth();
    56→  return userId;
    57→}
    58→
    59→export async function requireAdmin() {
    60→  const user = await currentUser();
    61→  if (!user) throw new Error("Unauthorized");
    62→  const role = user.publicMetadata?.role as string | undefined;
    63→  if (role !== "admin") throw new Error("Forbidden");
    64→  return user;
    65→}
