     1→import Anthropic from "@anthropic-ai/sdk";
     2→
     3→const client = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });
     4→
     5→export interface SynthesisInput {
     6→  studentId: string;
     7→  sessionId?: string;
     8→  activities: {
     9→    name: string;
    10→    category: string;
    11→    excitement?: number | null;
    12→    hoursPerWeek?: number | null;
    13→    isOngoing?: boolean;
    14→  }[];
    15→  reflections: {
    16→    promptText: string;
    17→    responseText?: string | null;
    18→    promptType: string;
    19→  }[];
    20→  previousProfile?: {
    21→    breadthScore: number;
    22→    interestClusters: unknown;
    23→    compressedSummary?: string | null;
    24→  } | null;
    25→}
    26→
    27→export interface SynthesisResult {
    28→  interestClusters: object[];
    29→  characterSignals: object[];
    30→  trajectoryShifts: object[];
    31→  gapDetection: object;
    32→  breadthScore: number;
    33→  compressedSummary: string;
    34→}
    35→
    36→function buildPrompt(input: SynthesisInput): string {
    37→  const today = new Date().toISOString().split("T")[0]!;
    38→
    39→  let activitiesText = "";
    40→  if (input.activities.length > 0) {
    41→    const lines = input.activities.map(
    42→      (a) =>
    43→        `- ${a.name} [${a.category}]: excitement ${a.excitement ?? "?"}/5, ${a.hoursPerWeek ?? "?"} hrs/wk, ongoing=${a.isOngoing ?? true}`
    44→    );
    45→    activitiesText = "ALL ACTIVITIES:\n" + lines.join("\n");
    46→  }
    47→
    48→  let reflectionsText = "";
    49→  if (input.reflections.length > 0) {
    50→    const lines = input.reflections
    51→      .filter((r) => r.responseText)
    52→      .slice(0, 15)
    53→      .map(
    54→        (r) =>
    55→          `[${r.promptType}] Q: ${r.promptText.slice(0, 100)}\nA: ${r.responseText!.slice(0, 400)}`
    56→      );
    57→    reflectionsText = "REFLECTION HISTORY:\n\n" + lines.join("\n\n");
    58→  }
    59→
    60→  let prevProfileText = "";
    61→  if (input.previousProfile) {
    62→    const clusters = Array.isArray(input.previousProfile.interestClusters)
    63→      ? (input.previousProfile.interestClusters as { label?: string }[]).map(
    64→          (c) => c.label
    65→        )
    66→      : [];
    67→    prevProfileText = `
    68→PREVIOUS SIGNAL PROFILE (for comparison/continuity):
    69→Breadth Score: ${input.previousProfile.breadthScore}
    70→Interest Clusters: ${JSON.stringify(clusters)}
    71→Previous summary: ${(input.previousProfile.compressedSummary ?? "").slice(0, 300)}
    72→`;
    73→  }
    74→
    75→  return `You are a longitudinal student analyst for COMPASS, an educational tool for high school students.
    76→Analyze this student's complete history to synthesize a signal profile.
    77→
    78→Date: ${today}
    79→
    80→${activitiesText}
    81→
    82→${reflectionsText}
    83→
    84→${prevProfileText}
    85→
    86→Synthesize a comprehensive signal profile. Your analysis must be:
    87→1. Evidence-based — cite specific activities/reflections
    88→2. Non-prescriptive — frame interests as "emerging" or "strong," never as fixed destiny
    89→3. Cross-domain aware — notice when technical + creative + social interests overlap
    90→4. Breadth-aware — score 0-100 based on domain diversity (not just number of activities)
    91→
    92→Breadth Score guidelines:
    93→- 0-20: Very narrow (1-2 domains)
    94→- 21-40: Developing breadth (3 domains)
    95→- 41-60: Moderate breadth (4-5 domains)
    96→- 61-80: Broad (6-7 diverse domains)
    97→- 81-100: Highly interdisciplinary (8+ domains with deep engagement)
    98→
    99→Respond with ONLY valid JSON matching this exact schema:
   100→{
   101→  "interestClusters": [
   102→    {
   103→      "id": "cluster-1",
   104→      "label": "Descriptive label",
   105→      "strength": "strong | moderate | emerging",
   106→      "evidenceCount": 3,
   107→      "domains": ["Technology"],
   108→      "lastSeen": "${today.slice(0, 7)}",
   109→      "trend": "rising | stable | declining"
   110→    }
   111→  ],
   112→  "characterSignals": [
   113→    {
   114→      "trait": "Trait name",
   115→      "description": "2-3 sentence description with specific evidence",
   116→      "evidenceExamples": ["Example 1", "Example 2"],
   117→      "confidence": "high | medium | low"
   118→    }
   119→  ],
   120→  "trajectoryShifts": [],
   121→  "gapDetection": {
   122→    "underexploredAreas": ["Area 1"],
   123→    "suggestedExpansions": ["Next step 1"],
   124→    "lastUpdated": "${today}"
   125→  },
   126→  "breadthScore": 45,
   127→  "compressedSummary": "300-400 word narrative summary in third person."
   128→}`;
   129→}
   130→
   131→export interface ReflectionPrompt {
   132→  promptText: string;
   133→  promptType: "PATTERN" | "EXPLORATION" | "IDENTITY" | "CHALLENGE";
   134→}
   135→
   136→export async function generateReflectionPrompts(input: {
   137→  compressedSummary?: string;
   138→  recentActivities: { name: string; category: string; excitement?: number | null; hoursPerWeek?: number | null }[];
   139→  recentReflections: { promptText: string; responseText?: string | null; promptType: string }[];
   140→  previousPrompts: string[];
   141→}): Promise<ReflectionPrompt[]> {
   142→  const today = new Date().toLocaleString("default", { month: "long", year: "numeric" });
   143→
   144→  const activityLines = input.recentActivities.slice(0, 10).map(
   145→    (a) => `- ${a.name} (${a.category}): excitement ${a.excitement ?? "?"}/5, ~${a.hoursPerWeek ?? "?"} hrs/week`
   146→  );
   147→  const activityText = activityLines.length
   148→    ? "Recent activities:\n" + activityLines.join("\n")
   149→    : "";
   150→
   151→  const recentAnswered = input.recentReflections
   152→    .filter((r) => r.responseText)
   153→    .slice(-3)
   154→    .map((r) => `[${r.promptType}] ${r.responseText!.slice(0, 200)}`);
   155→  const reflectionText = recentAnswered.length
   156→    ? "Recent reflection excerpts:\n" + recentAnswered.join("\n")
   157→    : "";
   158→
   159→  const prevPromptsText = input.previousPrompts.length
   160→    ? "Previously asked prompts (DO NOT repeat):\n" +
   161→      input.previousPrompts.slice(-10).map((p) => `- ${p}`).join("\n")
   162→    : "";
   163→
   164→  const profileText = input.compressedSummary
   165→    ? `Student signal profile:\n${input.compressedSummary}`
   166→    : "";
   167→
   168→  const prompt = `You are COMPASS, a reflection companion for high school students.
   169→Your role is to help students notice patterns in their own interests and expand their awareness — never to direct or prescribe.
   170→
   171→Current month: ${today}
   172→
   173→${profileText}
   174→
   175→${activityText}
   176→
   177→${reflectionText}
   178→
   179→${prevPromptsText}
   180→
   181→Generate 2-3 thoughtful reflection questions for this student.
   182→
   183→STRICT RULES:
   184→- Each question must be under 30 words
   185→- Never tell the student what they should do or pursue
   186→- Connect cross-domain interests when you see them
   187→- No repeats of previous prompts
   188→- Frame everything as curiosity and exploration, never judgment
   189→
   190→Question types: PATTERN, EXPLORATION, IDENTITY, CHALLENGE
   191→
   192→Respond with ONLY a JSON array:
   193→[{"promptText": "...", "promptType": "PATTERN"}, ...]`;
   194→
   195→  const message = await client.messages.create({
   196→    model: "claude-haiku-4-5-20251001",
   197→    max_tokens: 1024,
   198→    system:
   199→      "You are COMPASS, a reflection companion for high school students. Always respond with valid JSON only.",
   200→    messages: [{ role: "user", content: prompt }],
   201→  });
   202→
   203→  let content = (message.content[0] as { text: string }).text.trim();
   204→  if (content.startsWith("```")) {
   205→    const parts = content.split("```");
   206→    content = parts[1] ?? "";
   207→    if (content.startsWith("json")) content = content.slice(4);
   208→    content = content.trim();
   209→  }
   210→
   211→  const data = JSON.parse(content) as { promptText: string; promptType: string }[];
   212→  return data.map((p) => ({
   213→    promptText: p.promptText,
   214→    promptType: p.promptType as ReflectionPrompt["promptType"],
   215→  }));
   216→}
   217→
   218→export async function synthesizeProfile(
   219→  input: SynthesisInput
   220→): Promise<SynthesisResult> {
   221→  const message = await client.messages.create({
   222→    model: "claude-sonnet-4-6",
   223→    max_tokens: 4096,
   224→    system:
   225→      "You are a longitudinal student analyst. You identify patterns in students' interests, activities, and reflections to help them understand themselves better. Always respond with valid JSON only. Never prescribe what students should do.",
   226→    messages: [{ role: "user", content: buildPrompt(input) }],
   227→  });
   228→
   229→  let content = (message.content[0] as { text: string }).text.trim();
   230→
   231→  if (content.startsWith("```")) {
   232→    const parts = content.split("```");
   233→    content = parts[1] ?? "";
   234→    if (content.startsWith("json")) content = content.slice(4);
   235→    content = content.trim();
   236→  }
   237→
   238→  const data = JSON.parse(content) as Record<string, unknown>;
   239→
   240→  return {
   241→    interestClusters: (data.interestClusters as object[]) ?? [],
   242→    characterSignals: (data.characterSignals as object[]) ?? [],
   243→    trajectoryShifts: (data.trajectoryShifts as object[]) ?? [],
   244→    gapDetection: (data.gapDetection as object) ?? {},
   245→    breadthScore: typeof data.breadthScore === "number" ? data.breadthScore : 0,
   246→    compressedSummary:
   247→      typeof data.compressedSummary === "string" ? data.compressedSummary : "",
   248→  };
   249→}
