     1→import { NextResponse } from "next/server";
     2→import { requireStudent } from "@/lib/auth";
     3→import { prisma } from "@compass/db";
     4→
     5→const COOLDOWN_DAYS = 21;
     6→
     7→export async function POST() {
     8→  try {
     9→    const student = await requireStudent();
    10→    const now = new Date();
    11→
    12→    // Check for existing in-progress session
    13→    const inProgress = await prisma.reflectionSession.findFirst({
    14→      where: { studentId: student.id, completedAt: null },
    15→      orderBy: { createdAt: "desc" },
    16→    });
    17→    if (inProgress) {
    18→      return NextResponse.json(inProgress);
    19→    }
    20→
    21→    // Enforce 3-week cooldown from last completed session
    22→    const lastCompleted = await prisma.reflectionSession.findFirst({
    23→      where: { studentId: student.id, completedAt: { not: null } },
    24→      orderBy: { completedAt: "desc" },
    25→    });
    26→
    27→    if (lastCompleted?.completedAt) {
    28→      const unlockDate = new Date(lastCompleted.completedAt);
    29→      unlockDate.setDate(unlockDate.getDate() + COOLDOWN_DAYS);
    30→      if (unlockDate > now) {
    31→        const daysLeft = Math.ceil((unlockDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
    32→        return NextResponse.json(
    33→          { error: "cooldown", daysLeft },
    34→          { status: 403 }
    35→        );
    36→      }
    37→    }
    38→
    39→    // Find next available template for current year
    40→    const currentYear = String(now.getFullYear());
    41→    const startedTemplateIds = (
    42→      await prisma.reflectionSession.findMany({
    43→        where: { studentId: student.id, templateId: { not: null } },
    44→        select: { templateId: true },
    45→      })
    46→    ).map((s) => s.templateId!);
    47→
    48→    const nextTemplate = await prisma.reflectionTemplate.findFirst({
    49→      where: {
    50→        yearKey: currentYear,
    51→        isActive: true,
    52→        id: { notIn: startedTemplateIds },
    53→      },
    54→      orderBy: { orderNum: "asc" },
    55→    });
    56→
    57→    if (!nextTemplate) {
    58→      return NextResponse.json(
    59→        { error: "all_complete" },
    60→        { status: 403 }
    61→      );
    62→    }
    63→
    64→    // Count sessions to assign session number
    65→    const sessionCount = await prisma.reflectionSession.count({
    66→      where: { studentId: student.id },
    67→    });
    68→
    69→    const session = await prisma.reflectionSession.create({
    70→      data: {
    71→        studentId: student.id,
    72→        templateId: nextTemplate.id,
    73→        sessionNumber: sessionCount + 1,
    74→      },
    75→      include: {
    76→        activities: true,
    77→        reflections: true,
    78→        template: true,
    79→      },
    80→    });
    81→
    82→    return NextResponse.json(session);
    83→  } catch (error) {
    84→    const message = error instanceof Error ? error.message : "Unknown error";
    85→    return NextResponse.json({ error: message }, { status: 400 });
    86→  }
    87→}
    88→
    89→export async function GET() {
    90→  try {
    91→    const student = await requireStudent();
    92→
    93→    const sessions = await prisma.reflectionSession.findMany({
    94→      where: { studentId: student.id },
    95→      orderBy: { createdAt: "desc" },
    96→      include: {
    97→        template: { select: { title: true, orderNum: true } },
    98→        activities: { select: { id: true, name: true } },
    99→        reflections: {
   100→          select: {
   101→            id: true,
   102→            promptType: true,
   103→            wordCount: true,
   104→            createdAt: true,
   105→            isSharedWithCounselor: true,
   106→          },
   107→        },
   108→      },
   109→    });
   110→
   111→    return NextResponse.json(sessions);
   112→  } catch (error) {
   113→    const message = error instanceof Error ? error.message : "Unknown error";
   114→    return NextResponse.json({ error: message }, { status: 400 });
   115→  }
   116→}
