     1→import { NextResponse } from "next/server";
     2→import { requireStudent } from "@/lib/auth";
     3→import { prisma } from "@compass/db";
     4→import { z } from "zod";
     5→
     6→const updateSchema = z.object({
     7→  pulseScore: z.number().min(1).max(10).optional(),
     8→  pulseNote: z.string().max(500).optional(),
     9→});
    10→
    11→export async function GET(
    12→  _req: Request,
    13→  { params }: { params: Promise<{ id: string }> }
    14→) {
    15→  try {
    16→    const student = await requireStudent();
    17→    const { id } = await params;
    18→
    19→    const session = await prisma.reflectionSession.findFirst({
    20→      where: { id, studentId: student.id },
    21→      include: {
    22→        activities: { orderBy: { createdAt: "asc" } },
    23→        reflections: { orderBy: { createdAt: "asc" } },
    24→      },
    25→    });
    26→
    27→    if (!session) {
    28→      return NextResponse.json({ error: "Not found" }, { status: 404 });
    29→    }
    30→
    31→    return NextResponse.json(session);
    32→  } catch (error) {
    33→    const message = error instanceof Error ? error.message : "Unknown error";
    34→    return NextResponse.json({ error: message }, { status: 400 });
    35→  }
    36→}
    37→
    38→export async function PATCH(
    39→  req: Request,
    40→  { params }: { params: Promise<{ id: string }> }
    41→) {
    42→  try {
    43→    const student = await requireStudent();
    44→    const { id } = await params;
    45→    const body = await req.json();
    46→    const data = updateSchema.parse(body);
    47→
    48→    const session = await prisma.reflectionSession.updateMany({
    49→      where: { id, studentId: student.id },
    50→      data,
    51→    });
