    26→    if (!session) {
    27→      return NextResponse.json({ error: "Not found" }, { status: 404 });
    28→    }
    29→
    30→    if (session.completedAt) {
    31→      return NextResponse.json({ error: "Session already submitted" }, { status: 400 });
    32→    }
    33→
    34→    // Mark session as complete
    35→    const now = new Date();
    36→    const durationSeconds = Math.floor(
    37→      (now.getTime() - session.createdAt.getTime()) / 1000
    38→    );
    39→
    40→    await prisma.reflectionSession.update({
    41→      where: { id },
    42→      data: { completedAt: now, durationSeconds },
    43→    });
    44→
    45→    // Run synthesis directly (primary path — no external service dependency)
    46→    try {
    47→      const [activities, reflections, previousProfile] = await Promise.all([
    48→        prisma.activity.findMany({
    49→          where: { studentId: student.id },
    50→          orderBy: { createdAt: "asc" },
    51→        }),
    52→        prisma.reflection.findMany({
    53→          where: { studentId: student.id },
