    55→        }),
    56→        prisma.signalProfile.findFirst({
    57→          where: { studentId: student.id },
    58→          orderBy: { createdAt: "desc" },
    59→        }),
    60→      ]);
    61→
    62→      const synthesis = await synthesizeProfile({
    63→        studentId: student.id,
    64→        sessionId: id,
    65→        activities: activities.map((a) => ({
    66→          ...a,
    67→          hoursPerWeek: a.hoursPerWeek ? Number(a.hoursPerWeek) : null,
    68→        })),
    69→        reflections,
    70→        previousProfile,
    71→      });
    72→
    73→      await prisma.signalProfile.create({
    74→        data: {
    75→          studentId: student.id,
    76→          interestClusters: synthesis.interestClusters,
    77→          characterSignals: synthesis.characterSignals,
    78→          trajectoryShifts: synthesis.trajectoryShifts,
    79→          gapDetection: synthesis.gapDetection,
    80→          breadthScore: synthesis.breadthScore,
    81→          compressedSummary: synthesis.compressedSummary,
    82→          lastSynthesizedAt: new Date(),
    83→        },
    84→      });
