     8→export const dynamic = "force-dynamic";
     9→export const maxDuration = 60;
    10→
    11→function getQStash() {
    12→  return new Client({ token: process.env.QSTASH_TOKEN! });
    13→}
    14→
    15→interface QStashPayload {
    16→  type: "WEEKLY_NUDGE_SWEEP" | "OPPORTUNITY_SWEEP" | "POST_SESSION_SYNTHESIS";
    17→  data: Record<string, unknown>;
    18→  triggeredAt: string;
    19→}
    20→
    21→async function handler(req: Request) {
    22→  const body = (await req.json()) as QStashPayload;
    23→
    24→  switch (body.type) {
    25→    case "POST_SESSION_SYNTHESIS": {
    26→      const { studentId, sessionId } = body.data as {
    27→        studentId: string;
    28→        sessionId: string;
    29→      };
    30→      await handlePostSessionSynthesis(studentId, sessionId);
    31→      break;
    32→    }
    33→
    34→    case "WEEKLY_NUDGE_SWEEP": {
    35→      await handleWeeklyNudgeSweep();
    36→      break;
    37→    }
    38→
    39→    case "OPPORTUNITY_SWEEP": {
    40→      await handleOpportunitySweep();
    41→      break;
    42→    }
    43→
    44→    default:
    45→      return NextResponse.json(
    46→        { error: "Unknown job type" },
    47→        { status: 400 }
    48→      );
    49→  }
    50→
    51→  return NextResponse.json({ success: true });
    52→}
    53→
    54→async function handlePostSessionSynthesis(
    55→  studentId: string,
    56→  sessionId: string
    57→) {
    58→  // Fetch all relevant data
    59→  const [activities, reflections, previousProfile] = await Promise.all([
    60→    prisma.activity.findMany({
    61→      where: { studentId },
    62→      orderBy: { createdAt: "asc" },
    63→    }),
    64→    prisma.reflection.findMany({
    65→      where: { studentId },
    66→      orderBy: { createdAt: "asc" },
    67→    }),
    68→    prisma.signalProfile.findFirst({
    69→      where: { studentId },
    70→      orderBy: { createdAt: "desc" },
    71→    }),
    72→  ]);
    73→
    74→  const synthesis = await aiService.synthesizeProfile({
    75→    studentId,
    76→    sessionId,
    77→    activities,
    78→    reflections,
    79→    previousProfile,
    80→  });
    81→
    82→  // Save new signal profile
    83→  await prisma.signalProfile.create({
    84→    data: {
    85→      studentId,
    86→      interestClusters: synthesis.interestClusters as object[],
    87→      characterSignals: synthesis.characterSignals as object[],
    88→      trajectoryShifts: synthesis.trajectoryShifts as object[],
    89→      gapDetection: synthesis.gapDetection as object,
    90→      breadthScore: synthesis.breadthScore,
    91→      compressedSummary: synthesis.compressedSummary,
    92→      lastSynthesizedAt: new Date(),
    93→    },
    94→  });
    95→
    96→  // Invalidate caches
    97→  await Promise.all([
    98→    redis.del(CACHE_KEYS.signalProfile(studentId)),
    99→    redis.del(CACHE_KEYS.personalizedMap(studentId)),
   100→  ]);
   101→
   102→  // Enqueue embedding update if AI service is available
   103→  try {
   104→    const aiServiceUrl = process.env.AI_SERVICE_URL;
   105→    const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3000";
   106→    if (aiServiceUrl) {
   107→      await getQStash().publishJSON({
   108→        url: `${appUrl}/api/webhooks/qstash`,
   109→        body: {
   110→          type: "EMBED_PROFILE",
   111→          data: { studentId, summary: synthesis.compressedSummary },
   112→          triggeredAt: new Date().toISOString(),
   113→        },
   114→        delay: 5,
   115→      });
   116→    }
   117→  } catch {
   118→    // Non-critical: embedding is for personalized map, not core feature
   119→  }
   120→}
