   122→async function handleWeeklyNudgeSweep() {
   123→  const now = new Date();
   124→  const cutoff90Days = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
   125→  const cutoff48Hours = new Date(now.getTime() - 48 * 60 * 60 * 1000);
   126→  const cutoff72Hours = new Date(now.getTime() - 72 * 60 * 60 * 1000);
   127→
   128→  // Get all students with notification preferences enabled
   129→  const students = await prisma.student.findMany({
   130→    where: { onboardingCompleted: true },
   131→    include: {
   132→      notificationPrefs: true,
   133→      sessions: {
   134→        orderBy: { createdAt: "desc" },
   135→        take: 1,
   136→        select: { completedAt: true, createdAt: true },
   137→      },
   138→      notifications: {
   139→        where: {
   140→          type: "REFLECTION_NUDGE",
   141→          createdAt: { gte: cutoff48Hours },
   142→        },
   143→        take: 1,
   144→      },
   145→      signalProfiles: {
   146→        orderBy: { createdAt: "desc" },
   147→        take: 1,
   148→        select: { compressedSummary: true },
   149→      },
   150→    },
   151→  });
   152→
   153→  const weekKey = `${now.getFullYear()}-W${Math.ceil(now.getDate() / 7)}`;
   154→
   155→  for (const student of students) {
   156→    const prefs = student.notificationPrefs;
   157→    if (!prefs?.reflectionNudges) continue;
   158→
   159→    // Check weekly cap
   160→    const weeklyCount = (await redis.get(
   161→      `notif-count:${student.id}:${weekKey}`
   162→    )) as number | null;
   163→    if ((weeklyCount ?? 0) >= (prefs.maxPerWeek ?? 3)) continue;
   164→
   165→    // Check 48hr cooldown
   166→    if (student.notifications.length > 0) continue;
   167→
   168→    // Check 72hr post-session cooldown
   169→    const lastSession = student.sessions[0];
   170→    if (lastSession?.completedAt) {
   171→      const sessionCompletedAt = new Date(lastSession.completedAt);
   172→      if (sessionCompletedAt > cutoff72Hours) continue;
   173→
   174→      // Only nudge if it's been more than 35 days (approaching monthly)
   175→      const daysSinceSession = Math.floor(
   176→        (now.getTime() - sessionCompletedAt.getTime()) / (1000 * 60 * 60 * 24)
   177→      );
   178→      if (daysSinceSession < 25) continue;
   179→    }
   180→
   181→    // Check quiet hours
   182→    const hour = now.getHours();
   183→    const quietStart = parseInt(prefs.quietHoursStart?.split(":")[0] ?? "21");
   184→    const quietEnd = parseInt(prefs.quietHoursEnd?.split(":")[0] ?? "8");
   185→    const inQuietHours =
   186→      quietStart > quietEnd
   187→        ? hour >= quietStart || hour < quietEnd
   188→        : hour >= quietStart && hour < quietEnd;
   189→    if (inQuietHours) continue;
   190→
   191→    // Generate personalized notification
   192→    try {
   193→      const content = await aiService.generateNotification({
   194→        studentId: student.id,
   195→        triggerType: "REFLECTION_NUDGE",
   196→        compressedSummary:
   197→          student.signalProfiles[0]?.compressedSummary ?? undefined,
   198→      });
   199→
   200→      await prisma.notification.create({
   201→        data: {
   202→          studentId: student.id,
   203→          type: "REFLECTION_NUDGE",
   204→          title: content.title,
   205→          body: content.body,
   206→        },
   207→      });
   208→
   209→      // Increment weekly count
   210→      await redis.incr(`notif-count:${student.id}:${weekKey}`);
   211→      await redis.expire(
   212→        `notif-count:${student.id}:${weekKey}`,
   213→        60 * 60 * 24 * 7
   214→      );
   215→    } catch {
   216→      // Log and continue
   217→      console.error(`Failed to generate nudge for student ${student.id}`);
   218→    }
   219→  }
   220→}
   221→
   222→async function handleOpportunitySweep() {
   223→  // Find upcoming opportunities (programs with deadlines within 3 weeks)
   224→  const threeWeeksOut = new Date();
   225→  threeWeeksOut.setDate(threeWeeksOut.getDate() + 21);
   226→
   227→  // Get all students with signal profiles
   228→  const students = await prisma.student.findMany({
   229→    where: { onboardingCompleted: true },
   230→    include: {
   231→      signalProfiles: {
   232→        orderBy: { createdAt: "desc" },
   233→        take: 1,
   234→        select: { compressedSummary: true, interestClusters: true },
   235→      },
   236→      notificationPrefs: true,
   237→    },
   238→    take: 100,
   239→  });
   240→
   241→  // For each student with a profile, generate an opportunity notification
   242→  for (const student of students) {
   243→    const prefs = student.notificationPrefs;
   244→    if (!prefs?.opportunityAlerts) continue;
   245→
   246→    const profile = student.signalProfiles[0];
   247→    if (!profile?.compressedSummary) continue;
   248→
   249→    // Check weekly cap
   250→    const now = new Date();
   251→    const weekKey = `${now.getFullYear()}-W${Math.ceil(now.getDate() / 7)}`;
   252→    const weeklyCount = (await redis.get(
   253→      `notif-count:${student.id}:${weekKey}`
   254→    )) as number | null;
   255→    if ((weeklyCount ?? 0) >= (prefs.maxPerWeek ?? 3)) continue;
   256→
   257→    // Check for recent opportunity notification (7 days cooldown)
   258→    const recentOpportunity = await prisma.notification.findFirst({
   259→      where: {
   260→        studentId: student.id,
   261→        type: "OPPORTUNITY",
   262→        createdAt: {
   263→          gte: new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000),
   264→        },
   265→      },
   266→    });
   267→    if (recentOpportunity) continue;
   268→
   269→    try {
   270→      const content = await aiService.generateNotification({
   271→        studentId: student.id,
   272→        triggerType: "OPPORTUNITY",
   273→        compressedSummary: profile.compressedSummary,
   274→      });
   275→
   276→      await prisma.notification.create({
   277→        data: {
   278→          studentId: student.id,
   279→          type: "OPPORTUNITY",
   280→          title: content.title,
   281→          body: content.body,
   282→        },
   283→      });
   284→
   285→      await redis.incr(`notif-count:${student.id}:${weekKey}`);
   286→      await redis.expire(`notif-count:${student.id}:${weekKey}`, 60 * 60 * 24 * 7);
   287→    } catch {
   288→      console.error(`Failed opportunity sweep for student ${student.id}`);
   289→    }
   290→  }
   291→}
   292→
   293→// Lazily wrap handler to avoid Receiver construction at module load time
   294→// (which throws when QSTASH signing keys are missing during Next.js build)
   295→let wrappedHandler: ReturnType<typeof verifySignatureAppRouter> | null = null;
   296→
   297→export async function POST(req: Request) {
   298→  if (!wrappedHandler) {
   299→    wrappedHandler = verifySignatureAppRouter(handler);
   300→  }
   301→  return wrappedHandler(req);
   302→}
