     6→const querySchema = z.object({
     7→  page: z.coerce.number().default(1),
     8→  limit: z.coerce.number().max(100).default(20),
     9→  unreadOnly: z.coerce.boolean().default(false),
    10→});
    11→
    12→export async function GET(req: Request) {
    13→  try {
    14→    const student = await requireStudent();
    15→    const { searchParams } = new URL(req.url);
    16→
    17→    const { page, limit, unreadOnly } = querySchema.parse({
    18→      page: searchParams.get("page"),
    19→      limit: searchParams.get("limit"),
    20→      unreadOnly: searchParams.get("unreadOnly"),
    21→    });
    22→
    23→    const skip = (page - 1) * limit;
    24→
    25→    const [notifications, total] = await Promise.all([
    26→      prisma.notification.findMany({
    27→        where: {
    28→          studentId: student.id,
    29→          ...(unreadOnly ? { readAt: null } : {}),
    30→        },
    31→        orderBy: { createdAt: "desc" },
    32→        skip,
    33→        take: limit,
    34→        include: {
    35→          relatedNode: {
    36→            select: {
    37→              id: true,
    38→              type: true,
    39→              label: true,
    40→            },
    41→          },
    42→        },
    43→      }),
    44→      prisma.notification.count({
    45→        where: {
    46→          studentId: student.id,
    47→          ...(unreadOnly ? { readAt: null } : {}),
    48→        },
    49→      }),
    50→    ]);
    51→
    52→    return NextResponse.json({
    53→      notifications,
    54→      total,
    55→      page,
    56→      totalPages: Math.ceil(total / limit),
    57→    });
    58→  } catch (error) {
    59→    const message = error instanceof Error ? error.message : "Unknown error";
    60→    return NextResponse.json({ error: message }, { status: 400 });
