    69→  const [submitError, setSubmitError] = useState<string | null>(null);
    70→  const [localSession, setLocalSession] = useState(session);
    71→
    72→  const sessionTitle = session.template?.title
    73→    ? `Reflection ${session.template.orderNum}: ${session.template.title}`
    74→    : session.monthKey
    75→    ? new Date(
    76→        parseInt(session.monthKey.split("-")[0]!),
