     5→
     6→interface Reflection {
     7→  id: string;
     8→  promptText: string;
     9→  responseText: string | null;
    10→  promptType: string;
    11→  isSharedWithCounselor: boolean;
    12→}
    13→
    14→interface Session {
    15→  id: string;
    16→  reflections: Reflection[];
    17→  activities: unknown[];
    18→}
    19→
    20→interface Prompt {
    21→  promptText: string;
    22→  promptType: string;
    23→}
    24→
    25→export default function ReflectionPromptsStep({
    26→  session,
    27→  onNext,
    28→  onBack,
    29→}: {
    30→  session: Session;
    31→  onNext: (reflections: Reflection[]) => void;
    32→  onBack: () => void;
    33→}) {
    34→  const [prompts, setPrompts] = useState<Prompt[]>([]);
    35→  const [responses, setResponses] = useState<Record<number, string>>({});
    36→  const [savedIds, setSavedIds] = useState<Record<number, string>>({});
    37→  const [loadingPrompts, setLoadingPrompts] = useState(true);
    38→  const [saving, setSaving] = useState(false);
    39→  const autoSaveTimers = useRef<Record<number, NodeJS.Timeout>>({});
    40→
    41→  useEffect(() => {
    42→    async function fetchPrompts() {
    43→      try {
    44→        const res = await fetch("/api/sessions/prompts", {
    45→          method: "POST",
    46→          headers: { "Content-Type": "application/json" },
    47→          body: JSON.stringify({ sessionId: session.id }),
    48→        });
    49→
    50→        if (res.ok) {
    51→          const data = await res.json() as { prompts: (Prompt & { text?: string; type?: string })[] };
    52→          // Normalize template format {text, type} to {promptText, promptType}
    53→          setPrompts(
    54→            data.prompts.map((p) => ({
    55→              promptText: p.promptText ?? p.text ?? "",
    56→              promptType: p.promptType ?? p.type ?? "PATTERN",
    57→            }))
    58→          );
    59→        }
    60→      } catch {
    61→        // Fallback prompts
    62→        setPrompts([
    63→          {
    64→            promptText:
    65→              "What activity from this month felt most alive or energizing to you?",
    66→            promptType: "PATTERN",
    67→          },
    68→          {
    69→            promptText:
    70→              "What have you been curious about lately that you haven't had time to explore?",
    71→            promptType: "EXPLORATION",
    72→          },
    73→        ]);
    74→      } finally {
    75→        setLoadingPrompts(false);
    76→      }
    77→    }
    78→
    79→    fetchPrompts();
    80→  }, [session.id]);
    81→
    82→  function handleResponseChange(index: number, value: string) {
    83→    setResponses((prev) => ({ ...prev, [index]: value }));
    84→
    85→    // Auto-save with debounce
    86→    if (autoSaveTimers.current[index]) {
    87→      clearTimeout(autoSaveTimers.current[index]);
    88→    }
    89→    autoSaveTimers.current[index] = setTimeout(() => {
    90→      autoSave(index, value);
    91→    }, 3000);
    92→  }
    93→
    94→  async function autoSave(index: number, text: string) {
    95→    if (!prompts[index] || !text.trim()) return;
    96→
    97→    const prompt = prompts[index]!;
    98→
    99→    if (savedIds[index]) {
   100→      // Update existing reflection
   101→      await fetch(`/api/reflections/${savedIds[index]}`, {
   102→        method: "PATCH",
   103→        headers: { "Content-Type": "application/json" },
   104→        body: JSON.stringify({ responseText: text }),
   105→      });
   106→    } else {
   107→      // Create new reflection
   108→      const res = await fetch("/api/reflections", {
   109→        method: "POST",
   110→        headers: { "Content-Type": "application/json" },
   111→        body: JSON.stringify({
   112→          sessionId: session.id,
   113→          promptText: prompt.promptText,
   114→          responseText: text,
   115→          promptType: prompt.promptType,
   116→          isSharedWithCounselor: false,
   117→        }),
   118→      });
   119→
   120→      if (res.ok) {
   121→        const reflection = await res.json() as { id: string };
   122→        setSavedIds((prev) => ({ ...prev, [index]: reflection.id }));
   123→      }
   124→    }
   125→  }
   126→
   127→  async function handleNext() {
   128→    setSaving(true);
   129→    // Save any unsaved responses
   130→    for (let i = 0; i < prompts.length; i++) {
   131→      const response = responses[i];
   132→      if (response?.trim() && !savedIds[i]) {
   133→        await autoSave(i, response);
   134→      }
   135→    }
   136→
   137→    // Fetch updated reflections
   138→    const res = await fetch(`/api/sessions/${session.id}`);
   139→    if (res.ok) {
   140→      const updated = await res.json() as { reflections: Reflection[] };
   141→      onNext(updated.reflections);
   142→    } else {
   143→      onNext([]);
   144→    }
   145→    setSaving(false);
   146→  }
   147→
   148→  function wordCount(text: string): number {
   149→    return text.trim().split(/\s+/).filter(Boolean).length;
   150→  }
   151→
   152→  if (loadingPrompts) {
   153→    return (
   154→      <div className="glass-card p-8 text-center">
   155→        <div className="text-4xl mb-3 animate-pulse">✨</div>
   156→        <p className="text-[#6B7280] text-sm">
   157→          Loading your reflection...
   158→        </p>
   159→      </div>
   160→    );
   161→  }
   162→
   163→  return (
   164→    <div className="space-y-4">
   165→      <div className="glass-card p-5">
   166→        <h2 className="text-xl font-bold text-[#1A1A2E] mb-1">
   167→          Time to reflect
   168→        </h2>
   169→        <p className="text-sm text-[#6B7280] mb-5">
   170→          Answer as much or as little as feels right. No right or wrong.
   171→          Auto-saves as you type.
   172→        </p>
   173→
   174→        <div className="space-y-6">
   175→          {prompts.map((prompt, i) => (
   176→            <div key={i} className="space-y-2">
   177→              <div className="flex items-start gap-2">
   178→                <span className="flex-shrink-0 w-6 h-6 bg-[#3B82F6] text-white text-xs rounded-full flex items-center justify-center font-medium">
   179→                  {i + 1}
   180→                </span>
   181→                <p className="text-sm font-medium text-[#1A1A2E]">
   182→                  {prompt.promptText}
   183→                </p>
   184→              </div>
   185→              <div className="relative">
   186→                <textarea
   187→                  value={responses[i] ?? ""}
   188→                  onChange={(e) => handleResponseChange(i, e.target.value)}
   189→                  placeholder="Take your time..."
   190→                  rows={4}
   191→                  className="w-full px-4 py-3 bg-white/60 border border-gray-200/60 rounded-xl text-sm text-[#1A1A2E] placeholder-[#9CA3AF] focus:outline-none focus:ring-2 focus:ring-blue-500/40 resize-none"
   192→                />
   193→                <div className="absolute bottom-2 right-3 text-[10px] text-[#9CA3AF]">
   194→                  {wordCount(responses[i] ?? "")} words
   195→                  {savedIds[i] && (
   196→                    <span className="ml-2 text-emerald-500">✓ saved</span>
   197→                  )}
   198→                </div>
   199→              </div>
   200→            </div>
   201→          ))}
   202→        </div>
   203→      </div>
   204→
   205→      <div className="flex gap-3">
   206→        <Button onClick={onBack} variant="ghost" size="lg">
   207→          Back
   208→        </Button>
   209→        <Button
   210→          onClick={handleNext}
   211→          loading={saving}
   212→          variant="primary"
   213→          size="lg"
   214→          fullWidth
   215→        >
   216→          Continue →
   217→        </Button>
   218→      </div>
   219→    </div>
   220→  );
   221→}
