    99→          />
   100→        </div>
   101→
   102→        {/* Full reflection text (opt-in) */}
   103→        {answeredReflections.length > 0 && (
   104→          <div className="space-y-3">
   105→            <h3 className="text-sm font-semibold text-[#1A1A2E]">
