   144→        {/* Preview */}
   145→        <div className="mt-5 p-4 bg-gray-50/60 rounded-xl border border-gray-200/40">
   146→          <h3 className="text-xs font-semibold text-[#6B7280] uppercase tracking-wide mb-2">
