     1→import { NextResponse } from "next/server";
     2→import { requireStudent } from "@/lib/auth";
     3→import { prisma } from "@compass/db";
     4→import { z } from "zod";
     5→import { ActivityCategory } from "@compass/db";
     6→
     7→const onboardingSchema = z.object({
     8→  gradeLevel: z.number().min(9).max(12),
     9→  initialActivities: z
    10→    .array(
    11→      z.object({
    12→        category: z.nativeEnum(ActivityCategory),
    13→        name: z.string(),
    14→        hoursPerWeek: z.number().optional(),
    15→        excitement: z.number().min(1).max(5).optional(),
    16→      })
    17→    )
    18→    .optional(),
    19→});
    20→
    21→export async function POST(req: Request) {
    22→  try {
    23→    const student = await requireStudent();
    24→    const body = await req.json();
    25→    const data = onboardingSchema.parse(body);
    26→
    27→    // Update student grade + mark onboarding complete
    28→    await prisma.student.update({
    29→      where: { id: student.id },
    30→      data: {
    31→        gradeLevel: data.gradeLevel,
    32→        onboardingCompleted: true,
    33→      },
    34→    });
    35→
    36→    // Save initial activities if provided
    37→    if (data.initialActivities && data.initialActivities.length > 0) {
    38→      await prisma.activity.createMany({
    39→        data: data.initialActivities.map((a) => ({
    40→          studentId: student.id,
    41→          category: a.category,
    42→          name: a.name,
    43→          hoursPerWeek: a.hoursPerWeek,
    44→          excitement: a.excitement,
    45→          isOngoing: true,
    46→        })),
    47→      });
    48→    }
    49→
    50→    return NextResponse.json({ success: true });
    51→  } catch (error) {
    52→    const message = error instanceof Error ? error.message : "Unknown error";
    53→    return NextResponse.json({ error: message }, { status: 400 });
    54→  }
    55→}
