     1→"use client";
     2→
     3→import { useEffect, useRef, useState, useCallback } from "react";
     4→import * as d3 from "d3";
     5→import MapNodeDetail from "./MapNodeDetail";
     6→import MapSearchBar from "./MapSearchBar";
     7→import MapLegend from "./MapLegend";
     8→
     9→interface MapNode {
    10→  id: string;
    11→  type: string;
    12→  label: string;
    13→  description: string | null;
    14→  metadata: Record<string, unknown>;
    15→  similarity?: number;
    16→  isPersonalized?: boolean;
    17→  x?: number;
    18→  y?: number;
    19→  fx?: number | null;
    20→  fy?: number | null;
    21→  vx?: number;
    22→  vy?: number;
    23→}
    24→
    25→interface MapEdge {
    26→  source: string | MapNode;
    27→  target: string | MapNode;
    28→  weight: number;
    29→  edgeType: string;
    30→  id?: string;
    31→}
    32→
    33→const NODE_COLORS: Record<string, string> = {
    34→  CAREER: "#3B82F6",
    35→  MAJOR: "#8B5CF6",
    36→  INDUSTRY: "#10B981",
    37→  PROGRAM: "#F59E0B",
    38→  SKILL: "#EF4444",
    39→  VALUE: "#EC4899",
    40→};
    41→
    42→const NODE_SIZES: Record<string, number> = {
    43→  INDUSTRY: 18,
    44→  CAREER: 12,
    45→  MAJOR: 12,
    46→  PROGRAM: 10,
    47→  SKILL: 8,
    48→  VALUE: 8,
    49→};
    50→
    51→export default function MapCanvas() {
    52→  const svgRef = useRef<SVGSVGElement>(null);
    53→  const [nodes, setNodes] = useState<MapNode[]>([]);
    54→  const [edges, setEdges] = useState<MapEdge[]>([]);
    55→  const [selectedNode, setSelectedNode] = useState<MapNode | null>(null);
    56→  const [personalized, setPersonalized] = useState(true);
    57→  const [loading, setLoading] = useState(true);
    58→  const simulationRef = useRef<d3.Simulation<MapNode, MapEdge> | null>(null);
    59→
    60→  const fetchData = useCallback(async () => {
    61→    setLoading(true);
    62→    try {
    63→      const endpoint = personalized ? "/api/map/personalized" : "/api/map/nodes";
    64→      const res = await fetch(endpoint);
    65→      if (!res.ok) return;
    66→
    67→      const data = await res.json() as { nodes?: MapNode[]; edges?: MapEdge[] } | MapNode[];
    68→
    69→      if (Array.isArray(data)) {
    70→        setNodes(data);
    71→        // Fetch edges separately
    72→        const edgesRes = await fetch(
    73→          "/api/map/personalized"
    74→        );
    75→        if (edgesRes.ok) {
    76→          const edgeData = await edgesRes.json() as { edges: MapEdge[] };
    77→          setEdges(edgeData.edges ?? []);
    78→        }
    79→      } else {
    80→        setNodes(data.nodes ?? []);
    81→        setEdges(data.edges ?? []);
    82→      }
    83→    } finally {
    84→      setLoading(false);
    85→    }
    86→  }, [personalized]);
    87→
    88→  useEffect(() => {
    89→    fetchData();
    90→  }, [fetchData]);
    91→
    92→  useEffect(() => {
    93→    if (!svgRef.current || nodes.length === 0) return;
    94→
    95→    const container = svgRef.current.parentElement!;
    96→    const width = container.clientWidth;
    97→    const height = container.clientHeight;
    98→
    99→    const svg = d3.select(svgRef.current);
   100→    svg.selectAll("*").remove();
   101→
   102→    svg
   103→      .attr("width", width)
   104→      .attr("height", height)
   105→      .attr("viewBox", [0, 0, width, height]);
   106→
   107→    // Zoom/pan
   108→    const g = svg.append("g");
   109→
   110→    const zoom = d3.zoom<SVGSVGElement, unknown>()
   111→      .scaleExtent([0.2, 4])
   112→      .on("zoom", (event) => {
   113→        g.attr("transform", event.transform.toString());
   114→      });
   115→
   116→    svg.call(zoom);
   117→
   118→    // D3 Force Simulation
   119→    const simulation = d3
   120→      .forceSimulation<MapNode>(nodes)
   121→      .force(
   122→        "link",
   123→        d3
   124→          .forceLink<MapNode, MapEdge>(edges as MapEdge[])
   125→          .id((d) => d.id)
   126→          .distance((d) => 80 + (1 - (d.weight ?? 0.5)) * 60)
   127→          .strength(0.3)
   128→      )
   129→      .force("charge", d3.forceManyBody().strength(-200))
   130→      .force("center", d3.forceCenter(width / 2, height / 2))
   131→      .force(
   132→        "collision",
   133→        d3.forceCollide<MapNode>().radius((d) => (NODE_SIZES[d.type] ?? 10) + 15)
   134→      );
   135→
   136→    simulationRef.current = simulation;
   137→
   138→    // Draw edges
   139→    const link = g
   140→      .append("g")
   141→      .selectAll("line")
   142→      .data(edges)
   143→      .join("line")
   144→      .attr("stroke", "rgba(0,0,0,0.08)")
   145→      .attr("stroke-width", (d) => Math.max(0.5, (d.weight ?? 0.5) * 2))
   146→      .attr("class", "map-edge");
   147→
   148→    // Draw nodes
   149→    const nodeGroup = g
   150→      .append("g")
   151→      .selectAll("g")
   152→      .data(nodes)
   153→      .join("g")
   154→      .attr("class", "map-node")
   155→      // eslint-disable-next-line @typescript-eslint/no-explicit-any
   156→      .call(
   157→        d3
   158→          .drag<SVGGElement, MapNode>()
   159→          .on("start", (event, d) => {
   160→            if (!event.active) simulation.alphaTarget(0.3).restart();
   161→            d.fx = d.x;
   162→            d.fy = d.y;
   163→          })
   164→          .on("drag", (event, d) => {
   165→            d.fx = event.x;
   166→            d.fy = event.y;
   167→          })
   168→          .on("end", (event, d) => {
   169→            if (!event.active) simulation.alphaTarget(0);
   170→            d.fx = null;
   171→            d.fy = null;
   172→          }) as any
   173→      )
   174→      .on("click", (_event, d) => {
   175→        setSelectedNode(d);
   176→      });
   177→
   178→    // Node circles
   179→    nodeGroup
   180→      .append("circle")
   181→      .attr("r", (d) => {
   182→        const base = NODE_SIZES[d.type] ?? 10;
   183→        const boost = d.similarity ? d.similarity * 8 : 0;
   184→        return base + boost;
   185→      })
   186→      .attr("fill", (d) => NODE_COLORS[d.type] ?? "#6B7280")
   187→      .attr("fill-opacity", (d) => (d.isPersonalized ? 0.9 : 0.6))
   188→      .attr("stroke", (d) => (d.isPersonalized ? "white" : "none"))
   189→      .attr("stroke-width", 2)
   190→      .style("cursor", "pointer")
   191→      .style("filter", (d) =>
   192→        d.isPersonalized
   193→          ? `drop-shadow(0 0 6px ${NODE_COLORS[d.type] ?? "#3B82F6"}66)`
   194→          : "none"
   195→      );
   196→
   197→    // Node labels
   198→    nodeGroup
   199→      .append("text")
   200→      .attr("y", (d) => (NODE_SIZES[d.type] ?? 10) + 12)
   201→      .attr("text-anchor", "middle")
   202→      .attr("font-size", "10px")
   203→      .attr("font-family", "Inter, system-ui, sans-serif")
   204→      .attr("fill", "#1A1A2E")
   205→      .attr("pointer-events", "none")
   206→      .text((d) =>
   207→        d.label.length > 20 ? d.label.slice(0, 18) + "..." : d.label
   208→      );
   209→
   210→    // Simulation tick
   211→    simulation.on("tick", () => {
   212→      link
   213→        .attr("x1", (d) => (typeof d.source === "object" ? d.source.x ?? 0 : 0))
   214→        .attr("y1", (d) => (typeof d.source === "object" ? d.source.y ?? 0 : 0))
   215→        .attr("x2", (d) => (typeof d.target === "object" ? d.target.x ?? 0 : 0))
   216→        .attr("y2", (d) => (typeof d.target === "object" ? d.target.y ?? 0 : 0));
   217→
   218→      nodeGroup.attr("transform", (d) => `translate(${d.x ?? 0},${d.y ?? 0})`);
   219→    });
   220→
   221→    return () => {
   222→      simulation.stop();
   223→    };
   224→  }, [nodes, edges]);
