     7→const COOLDOWN_DAYS = 21;
     8→
     9→export default async function ReflectPage() {
    10→  const student = await requireStudent();
    11→  const now = new Date();
    12→
    13→  // Resume in-progress session if any
    14→  const inProgress = await prisma.reflectionSession.findFirst({
    15→    where: { studentId: student.id, completedAt: null },
    16→    orderBy: { createdAt: "desc" },
    17→  });
    18→  if (inProgress) {
    19→    redirect(`/reflect/${inProgress.id}`);
    20→  }
    21→
    22→  // Get last completed session for cooldown check
    23→  const lastCompleted = await prisma.reflectionSession.findFirst({
    24→    where: { studentId: student.id, completedAt: { not: null } },
    25→    orderBy: { completedAt: "desc" },
    26→    include: { template: { select: { title: true, orderNum: true } } },
    27→  });
    28→
    29→  // Check cooldown
    30→  let daysLeft = 0;
    31→  if (lastCompleted?.completedAt) {
    32→    const unlockDate = new Date(lastCompleted.completedAt);
    33→    unlockDate.setDate(unlockDate.getDate() + COOLDOWN_DAYS);
    34→    daysLeft = Math.max(0, Math.ceil((unlockDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24)));
    35→  }
    36→
    37→  // Find next available template
    38→  const currentYear = String(now.getFullYear());
    39→  const startedTemplateIds = (
    40→    await prisma.reflectionSession.findMany({
    41→      where: { studentId: student.id, templateId: { not: null } },
    42→      select: { templateId: true },
    43→    })
    44→  ).map((s) => s.templateId!);
    45→
    46→  const nextTemplate = await prisma.reflectionTemplate.findFirst({
    47→    where: { yearKey: currentYear, isActive: true, id: { notIn: startedTemplateIds } },
    48→    orderBy: { orderNum: "asc" },
    49→  });
    50→
    51→  const totalTemplates = await prisma.reflectionTemplate.count({
    52→    where: { yearKey: currentYear, isActive: true },
    53→  });
    54→
    55→  const completedCount = startedTemplateIds.length;
    56→
    57→  // All done for the year
    58→  if (!nextTemplate) {
    59→    return (
    60→      <div className="min-h-[60vh] flex items-center justify-center">
    61→        <div className="glass-card p-8 text-center max-w-sm">
    62→          <div className="text-5xl mb-4">🎉</div>
    63→          <h2 className="text-xl font-bold text-[#1A1A2E] mb-2">
    64→            All reflections complete for {currentYear}
    65→          </h2>
    66→          <p className="text-[#6B7280] text-sm mb-6">
    67→            You&apos;ve finished all {totalTemplates} reflections this year. Check back next year.
    68→          </p>
    69→          <Link href="/" className="btn-primary">Back to Home</Link>
    70→        </div>
    71→      </div>
    72→    );
    73→  }
    74→
    75→  // In cooldown
    76→  if (daysLeft > 0) {
    77→    return (
    78→      <div className="min-h-[60vh] flex items-center justify-center">
    79→        <div className="glass-card p-8 text-center max-w-sm">
    80→          <div className="w-16 h-16 rounded-full bg-blue-100 flex items-center justify-center text-2xl font-bold text-[#3B82F6] mx-auto mb-4">
    81→            {daysLeft}
    82→          </div>
    83→          <h2 className="text-xl font-bold text-[#1A1A2E] mb-2">
    84→            Next reflection opens in {daysLeft} day{daysLeft !== 1 ? "s" : ""}
    85→          </h2>
    86→          <p className="text-[#6B7280] text-sm mb-2">
    87→            Up next: <span className="font-medium text-[#1A1A2E]">Reflection {nextTemplate.orderNum}: {nextTemplate.title}</span>
    88→          </p>
    89→          <p className="text-xs text-[#9CA3AF] mb-6">
    90→            {completedCount} of {totalTemplates} reflections done this year
    91→          </p>
    92→          <Link href="/" className="btn-primary">Back to Home</Link>
    93→        </div>
    94→      </div>
    95→    );
    96→  }
    97→
    98→  // Ready to start next reflection
    99→  return (
   100→    <div className="min-h-[60vh] flex items-center justify-center">
   101→      <div className="glass-card p-8 text-center max-w-sm">
   102→        <div className="text-5xl mb-4">🧭</div>
   103→        <p className="text-xs text-[#9CA3AF] mb-1 uppercase tracking-wide font-medium">
   104→          Reflection {nextTemplate.orderNum} of {totalTemplates}
   105→        </p>
   106→        <h2 className="text-xl font-bold text-[#1A1A2E] mb-2">
   107→          {nextTemplate.title}
   108→        </h2>
   109→        {nextTemplate.description && (
   110→          <p className="text-[#6B7280] text-sm mb-6">{nextTemplate.description}</p>
   111→        )}
   112→        {!nextTemplate.description && (
   113→          <p className="text-[#6B7280] text-sm mb-6">
   114→            10–15 minutes to capture what&apos;s been on your mind.
   115→          </p>
   116→        )}
   117→        <StartSessionButton />
   118→      </div>
   119→    </div>
   120→  );
   121→}
