    16→});
    17→
    18→export async function PUT(
    19→  req: Request,
    20→  { params }: { params: Promise<{ id: string }> }
    21→) {
    22→  try {
    23→    const student = await requireStudent();
    24→    const { id } = await params;
    25→    const body = await req.json();
    26→    const data = updateSchema.parse(body);
    27→
    28→    const result = await prisma.activity.updateMany({
    29→      where: { id, studentId: student.id },
    30→      data: {
    31→        ...data,
    32→        startDate: data.startDate ? new Date(data.startDate) : data.startDate === null ? null : undefined,
    33→        endDate: data.endDate ? new Date(data.endDate) : data.endDate === null ? null : undefined,
    34→      },
    35→    });
    36→
    37→    if (result.count === 0) {
    38→      return NextResponse.json({ error: "Not found" }, { status: 404 });
    39→    }
    40→
    41→    return NextResponse.json({ success: true });
    42→  } catch (error) {
    43→    const message = error instanceof Error ? error.message : "Unknown error";
    44→    return NextResponse.json({ error: message }, { status: 400 });
    45→  }
    46→}
