    22→const PROMPT_TYPES = ["PATTERN", "EXPLORATION", "IDENTITY", "CHALLENGE"] as const;
    23→
    24→const CURRENT_YEAR = String(new Date().getFullYear());
    25→
    26→function emptyPrompt(): Prompt {
    27→  return { promptText: "", promptType: "PATTERN" };
    28→}
    29→
    30→function parsePrompts(raw: unknown): Prompt[] {
    31→  if (!Array.isArray(raw)) return [emptyPrompt()];
    32→  return raw.map((p) => ({
    33→    promptText: (p as Prompt).promptText ?? "",
    34→    promptType: (p as Prompt).promptType ?? "PATTERN",
    35→  }));
    36→}
    37→
    38→function TemplateForm({
    39→  initial,
    40→  existingOrders,
    41→  onSave,
    42→  onCancel,
    43→}: {
    44→  initial?: Partial<Template>;
    45→  existingOrders: number[];
    46→  onSave: (data: object) => Promise<void>;
    47→  onCancel: () => void;
    48→}) {
    49→  const [title, setTitle] = useState(initial?.title ?? "");
    50→  const [description, setDescription] = useState(initial?.description ?? "");
    51→  const [orderNum, setOrderNum] = useState(initial?.orderNum ?? (Math.max(0, ...existingOrders) + 1));
    52→  const [yearKey, setYearKey] = useState(initial?.yearKey ?? CURRENT_YEAR);
    53→  const [prompts, setPrompts] = useState<Prompt[]>(
    54→    initial?.prompts ? parsePrompts(initial.prompts) : [emptyPrompt(), emptyPrompt()]
    55→  );
    56→  const [saving, setSaving] = useState(false);
    57→  const [error, setError] = useState<string | null>(null);
    58→
    59→  function updatePrompt(i: number, field: keyof Prompt, value: string) {
    60→    setPrompts((prev) => prev.map((p, idx) => (idx === i ? { ...p, [field]: value } : p)));
    61→  }
    62→
    63→  function addPrompt() {
    64→    setPrompts((prev) => [...prev, emptyPrompt()]);
    65→  }
    66→
    67→  function removePrompt(i: number) {
    68→    setPrompts((prev) => prev.filter((_, idx) => idx !== i));
    69→  }
    70→
    71→  async function handleSave() {
    72→    if (!title.trim() || prompts.some((p) => !p.promptText.trim())) {
    73→      setError("Title and all prompt texts are required.");
    74→      return;
    75→    }
    76→    setSaving(true);
    77→    setError(null);
    78→    try {
    79→      await onSave({ title, description, orderNum, yearKey, prompts });
    80→    } catch (e) {
    81→      setError(e instanceof Error ? e.message : "Save failed");
    82→    } finally {
    83→      setSaving(false);
    84→    }
    85→  }
    86→
    87→  return (
    88→    <div className="border border-gray-200 rounded-2xl p-5 space-y-4 bg-white">
    89→      <div className="grid grid-cols-2 gap-3">
    90→        <div>
    91→          <label className="text-xs font-medium text-[#6B7280] block mb-1">Title</label>
    92→          <input
    93→            value={title}
    94→            onChange={(e) => setTitle(e.target.value)}
    95→            placeholder="e.g. Finding Your Threads"
    96→            className="w-full px-3 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/40"
    97→          />
    98→        </div>
    99→        <div className="grid grid-cols-2 gap-2">
   100→          <div>
   101→            <label className="text-xs font-medium text-[#6B7280] block mb-1">Order #</label>
   102→            <input
   103→              type="number"
   104→              value={orderNum}
   105→              onChange={(e) => setOrderNum(parseInt(e.target.value) || 1)}
   106→              min={1}
   107→              className="w-full px-3 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/40"
   108→            />
   109→          </div>
   110→          <div>
   111→            <label className="text-xs font-medium text-[#6B7280] block mb-1">Year</label>
   112→            <input
   113→              value={yearKey}
   114→              onChange={(e) => setYearKey(e.target.value)}
   115→              placeholder="2026"
   116→              className="w-full px-3 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/40"
   117→            />
   118→          </div>
   119→        </div>
   120→      </div>
   121→
   122→      <div>
   123→        <label className="text-xs font-medium text-[#6B7280] block mb-1">Description (shown to student before starting)</label>
   124→        <input
   125→          value={description}
   126→          onChange={(e) => setDescription(e.target.value)}
   127→          placeholder="Optional — what this reflection is about"
   128→          className="w-full px-3 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/40"
   129→        />
   130→      </div>
   131→
   132→      <div className="space-y-3">
   133→        <label className="text-xs font-medium text-[#6B7280] block">Prompts</label>
   134→        {prompts.map((p, i) => (
   135→          <div key={i} className="flex gap-2 items-start">
   136→            <span className="flex-shrink-0 w-5 h-5 mt-2 bg-[#3B82F6] text-white text-[10px] rounded-full flex items-center justify-center font-medium">
   137→              {i + 1}
   138→            </span>
   139→            <div className="flex-1 space-y-1.5">
   140→              <textarea
   141→                value={p.promptText}
   142→                onChange={(e) => updatePrompt(i, "promptText", e.target.value)}
   143→                placeholder="Write your reflection prompt here..."
   144→                rows={2}
   145→                className="w-full px-3 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/40 resize-none"
   146→              />
   147→              <select
   148→                value={p.promptType}
   149→                onChange={(e) => updatePrompt(i, "promptType", e.target.value)}
   150→                className="px-2 py-1 border border-gray-200 rounded-lg text-xs text-[#6B7280] focus:outline-none"
   151→              >
   152→                {PROMPT_TYPES.map((t) => (
   153→                  <option key={t} value={t}>{t}</option>
   154→                ))}
   155→              </select>
   156→            </div>
   157→            {prompts.length > 1 && (
   158→              <button onClick={() => removePrompt(i)} className="mt-2 text-red-400 hover:text-red-600 text-sm">×</button>
   159→            )}
   160→          </div>
   161→        ))}
   162→        <button
   163→          onClick={addPrompt}
   164→          className="text-sm text-[#3B82F6] hover:underline"
   165→        >
   166→          + Add prompt
   167→        </button>
   168→      </div>
   169→
   170→      {error && <p className="text-sm text-red-600">{error}</p>}
   171→
   172→      <div className="flex gap-2 justify-end">
   173→        <button onClick={onCancel} className="px-4 py-2 text-sm text-[#6B7280] hover:text-[#1A1A2E]">
   174→          Cancel
   175→        </button>
   176→        <button
   177→          onClick={handleSave}
   178→          disabled={saving}
   179→          className="px-4 py-2 text-sm bg-[#3B82F6] text-white rounded-xl hover:bg-[#2563EB] disabled:opacity-60"
   180→        >
   181→          {saving ? "Saving..." : "Save Template"}
   182→        </button>
   183→      </div>
   184→    </div>
   185→  );
   186→}
   187→
   188→export default function TemplateManager({ templates: initial }: { templates: Template[] }) {
   189→  const router = useRouter();
   190→  const [templates, setTemplates] = useState(initial);
   191→  const [creating, setCreating] = useState(false);
   192→  const [editingId, setEditingId] = useState<string | null>(null);
   193→
   194→  const existingOrders = templates.map((t) => t.orderNum);
   195→
   196→  async function handleCreate(data: object) {
   197→    const res = await fetch("/api/admin/templates", {
   198→      method: "POST",
   199→      headers: { "Content-Type": "application/json" },
   200→      body: JSON.stringify(data),
   201→    });
   202→    if (!res.ok) {
   203→      const err = await res.json() as { error: string };
   204→      throw new Error(err.error);
   205→    }
   206→    setCreating(false);
   207→    router.refresh();
   208→  }
   209→
   210→  async function handleUpdate(id: string, data: object) {
   211→    const res = await fetch(`/api/admin/templates/${id}`, {
   212→      method: "PATCH",
   213→      headers: { "Content-Type": "application/json" },
   214→      body: JSON.stringify(data),
   215→    });
   216→    if (!res.ok) {
   217→      const err = await res.json() as { error: string };
   218→      throw new Error(err.error);
   219→    }
   220→    setEditingId(null);
   221→    router.refresh();
   222→  }
   223→
   224→  async function handleDelete(id: string) {
   225→    if (!confirm("Delete this template? Students who haven't started it will no longer see it.")) return;
   226→    await fetch(`/api/admin/templates/${id}`, { method: "DELETE" });
   227→    setTemplates((prev) => prev.filter((t) => t.id !== id));
   228→  }
   229→
   230→  async function handleToggleActive(t: Template) {
   231→    await fetch(`/api/admin/templates/${t.id}`, {
   232→      method: "PATCH",
   233→      headers: { "Content-Type": "application/json" },
   234→      body: JSON.stringify({ isActive: !t.isActive }),
   235→    });
   236→    router.refresh();
   237→  }
   238→
   239→  return (
   240→    <div className="space-y-4">
   241→      {templates.map((t) => (
   242→        <div key={t.id} className={`border rounded-2xl p-4 ${t.isActive ? "border-gray-200 bg-white" : "border-gray-100 bg-gray-50 opacity-60"}`}>
   243→          {editingId === t.id ? (
   244→            <TemplateForm
   245→              initial={t}
   246→              existingOrders={existingOrders.filter((o) => o !== t.orderNum)}
   247→              onSave={(data) => handleUpdate(t.id, data)}
   248→              onCancel={() => setEditingId(null)}
   249→            />
   250→          ) : (
   251→            <div>
   252→              <div className="flex items-start justify-between gap-3">
   253→                <div>
   254→                  <div className="flex items-center gap-2">
   255→                    <span className="text-xs font-medium text-[#9CA3AF]">{t.yearKey} · #{t.orderNum}</span>
   256→                    {!t.isActive && <span className="text-[10px] px-2 py-0.5 bg-gray-200 text-gray-500 rounded-full">Inactive</span>}
   257→                  </div>
   258→                  <h3 className="font-semibold text-[#1A1A2E] mt-0.5">{t.title}</h3>
   259→                  {t.description && <p className="text-sm text-[#6B7280] mt-0.5">{t.description}</p>}
   260→                  <p className="text-xs text-[#9CA3AF] mt-1">
   261→                    {parsePrompts(t.prompts).length} prompt{parsePrompts(t.prompts).length !== 1 ? "s" : ""} · {t._count.sessions} session{t._count.sessions !== 1 ? "s" : ""} started
   262→                  </p>
   263→                </div>
   264→                <div className="flex items-center gap-2 flex-shrink-0">
   265→                  <button onClick={() => handleToggleActive(t)} className="text-xs text-[#6B7280] hover:text-[#1A1A2E]">
   266→                    {t.isActive ? "Deactivate" : "Activate"}
   267→                  </button>
   268→                  <button onClick={() => setEditingId(t.id)} className="text-xs text-[#3B82F6] hover:underline">
   269→                    Edit
   270→                  </button>
   271→                  <button onClick={() => handleDelete(t.id)} className="text-xs text-red-400 hover:text-red-600">
   272→                    Delete
   273→                  </button>
   274→                </div>
   275→              </div>
   276→              <div className="mt-3 space-y-1.5">
   277→                {parsePrompts(t.prompts).map((p, i) => (
   278→                  <div key={i} className="flex items-start gap-2">
   279→                    <span className="text-[10px] px-1.5 py-0.5 bg-blue-50 text-blue-600 rounded font-medium flex-shrink-0 mt-0.5">{p.promptType}</span>
   280→                    <p className="text-sm text-[#374151]">{p.promptText}</p>
   281→                  </div>
   282→                ))}
   283→              </div>
   284→            </div>
   285→          )}
   286→        </div>
   287→      ))}
   288→
   289→      {creating ? (
   290→        <TemplateForm
   291→          existingOrders={existingOrders}
   292→          onSave={handleCreate}
   293→          onCancel={() => setCreating(false)}
   294→        />
   295→      ) : (
   296→        <button
   297→          onClick={() => setCreating(true)}
   298→          className="w-full py-3 border-2 border-dashed border-gray-200 rounded-2xl text-sm text-[#6B7280] hover:border-blue-300 hover:text-[#3B82F6] transition-colors"
   299→        >
   300→          + New Template
   301→        </button>
   302→      )}
   303→    </div>
   304→  );
   305→}
